// =============================================
// STEP 1: GET ALL AGENT OUTPUTS
// =============================================
var briefData = $('AI Agent1').first().json.output || '';
var researchData = $('AI Agent2').first().json.output || '';
var firstHalf = $('AI Agent 3A').first().json.output || '';
var secondHalf = $('AI Agent 3B').first().json.output || '';

// Combine both halves
var reportContent = firstHalf + '\n\n' + secondHalf;

// =============================================
// STEP 2: PARSE BRIEF JSON
// =============================================
var briefJSON = {};
try {
  briefJSON = JSON.parse(briefData);
} catch (e) {
  var jsonMatch = briefData.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      briefJSON = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      briefJSON = {};
    }
  }
}

var university = briefJSON.university_name || 'University';
var moduleName = briefJSON.module_name || 'Module';
var moduleCode = briefJSON.module_code || '';
var moduleLead = briefJSON.module_lead || '';
var refStyle = briefJSON.referencing_style || '';
var submissionDate = briefJSON.submission_date || '';
var assignmentTitle = briefJSON.assignment_title || 'Assignment';
var academicLevel = briefJSON.academic_level || '';

// =============================================
// STEP 3: EXTRACT WORD COUNT
// =============================================
var requiredWordCount = 2000;

if (briefJSON.word_count) {
  var wcFromJSON = parseInt(String(briefJSON.word_count).replace(/[^0-9]/g, ''));
  if (wcFromJSON && wcFromJSON >= 500) {
    requiredWordCount = wcFromJSON;
  }
}

if (requiredWordCount === 2000) {
  var wcMatch = researchData.match(/TARGET WORD COUNT[:\s]*([0-9,]+)/i);
  if (wcMatch) {
    var wcFromResearch = parseInt(wcMatch[1].replace(/,/g, ''));
    if (wcFromResearch && wcFromResearch >= 500) {
      requiredWordCount = wcFromResearch;
    }
  }
}

// =============================================
// STEP 4: CLEAN UP AGENT OUTPUT
// =============================================
reportContent = reportContent.replace(/\(\d+\s*words?\)/gi, '');
reportContent = reportContent.replace(/\(approximately\s*\d+\s*words?\)/gi, '');
reportContent = reportContent.replace(/\[?\d+\s*words?\]?/gi, function(match) {
  if (match.match(/^\[?\d+\s*words?\]?$/i)) return '';
  return match;
});

var instructionPatterns = [
  /^Write ONLY.*$/gm,
  /^Stop after section.*$/gm,
  /^Do NOT write.*$/gm,
  /^Start directly.*$/gm,
  /^Continue the report.*$/gm,
  /^NOW WRITE ONLY.*$/gm,
  /^WRITE ONLY.*$/gm,
  /^Rules:.*$/gm,
  /^TARGET WORD COUNT.*$/gm,
  /^TOTAL FOR THIS HALF.*$/gm,
  /^Note:.*verify.*$/gmi,
  /^Note:.*URL.*$/gmi,
  /^\(Note:.*\)$/gm,
  /\[Full URL needed\]/gi,
  /\[Full URL\]/gi,
  /^INSTRUCTIONS:.*$/gm,
  /^STRICT RULES:.*$/gm,
  /^RESEARCH PACKAGE:.*$/gm,
  /^BRIEF REQUIREMENTS.*$/gm,
  /^FIRST HALF:.*$/gm,
  /^End of Section.*$/gm,
  /^\(≈\).*$/gm,
  /\(≈\)/g
];

for (var ip = 0; ip < instructionPatterns.length; ip++) {
  reportContent = reportContent.replace(instructionPatterns[ip], '');
}

reportContent = reportContent.replace(/\n{4,}/g, '\n\n\n');

// =============================================
// STEP 5: COUNT WORDS
// =============================================
var allWords = reportContent.split(/\s+/).filter(function(w) { return w.length > 0; });
var actualWordCount = allWords.length;

// =============================================
// STEP 6: COUNT TABLES
// =============================================
var tableMatches = reportContent.match(/Table\s+\d+/gi) || [];
var seenTables = {};
var tableCount = 0;
for (var t = 0; t < tableMatches.length; t++) {
  var tkey = tableMatches[t].toLowerCase();
  if (!seenTables[tkey]) {
    seenTables[tkey] = true;
    tableCount++;
  }
}

// =============================================
// STEP 7: COUNT REFERENCES
// =============================================
var refCount = 0;
var refSectionText = '';

var refSplitPatterns = [
  /\n#{1,3}\s*References?\s*\n/i,
  /\nReferences?\s*\n/i,
  /\n\*\*References?\*\*\s*\n/i,
  /\nReference List\s*\n/i,
  /\n#{1,3}\s*Bibliography\s*\n/i
];

for (var rp = 0; rp < refSplitPatterns.length; rp++) {
  var refSplit = reportContent.split(refSplitPatterns[rp]);
  if (refSplit.length > 1) {
    refSectionText = refSplit[refSplit.length - 1];
    break;
  }
}

if (refSectionText) {
  var refLines = refSectionText.split('\n');
  for (var r = 0; r < refLines.length; r++) {
    var rl = refLines[r].trim();
    if (rl.length > 20 && rl.match(/\(\d{4}\)/)) {
      refCount++;
    } else if (rl.length > 20 && rl.match(/\d{4}[.)]/)) {
      refCount++;
    } else if (rl.length > 20 && rl.match(/\.\s*\(\d{4}\)\./)) {
      refCount++;
    }
    if (rl.match(/^#{1,3}\s+/) && !rl.toLowerCase().includes('reference') && !rl.toLowerCase().includes('bibliography')) {
      break;
    }
  }
}

if (refCount === 0) {
  var allRefLines = reportContent.split('\n');
  var inRefSection = false;
  for (var ar = 0; ar < allRefLines.length; ar++) {
    var arl = allRefLines[ar].trim().toLowerCase();
    if (arl === 'references' || arl === '## references' || arl === '### references' ||
        arl === '**references**' || arl === 'reference list' || arl === '## reference list') {
      inRefSection = true;
      continue;
    }
    if (inRefSection) {
      var origLine = allRefLines[ar].trim();
      if (origLine.length > 20 && origLine.match(/\d{4}/)) {
        refCount++;
      }
      if (origLine.match(/^#{1,3}\s+/) && !origLine.toLowerCase().includes('reference')) {
        break;
      }
    }
  }
}

// =============================================
// STEP 8: COUNT CITATIONS
// =============================================
var citationMatches = reportContent.match(/\([A-Z][a-z]+[^)]*\d{4}[^)]*\)/g) || [];
var citationCount = citationMatches.length;

if (citationCount === 0) {
  var vanCitations = reportContent.match(/\[\d+\]/g) || [];
  citationCount = vanCitations.length;
}

// =============================================
// STEP 9: QUALITY CHECKS
// =============================================
var wordOk = actualWordCount >= (requiredWordCount * 0.85) && actualWordCount <= (requiredWordCount * 1.15);
var wordClose = actualWordCount >= (requiredWordCount * 0.75);
var referencingAllowed = refStyle && refStyle.toLowerCase() !== 'none' && refStyle.toLowerCase() !== 'n/a';
var tablesOk = tableCount >= 1;
var refsOk = referencingAllowed ? refCount >= 3 : true;
var citationsOk = referencingAllowed ? citationCount >= 5 : true;
var allPassed = wordClose && refsOk;

// =============================================
// STEP 10: CONVERT MARKDOWN TO CLEAN HTML
// =============================================
var htmlLines = reportContent.split('\n');
var htmlResult = [];
var inHtmlTable = false;
var htmlTableContent = '';
var isHtmlFirstRow = true;

// Track headings for Table of Contents
var tocEntries = [];

for (var hi = 0; hi < htmlLines.length; hi++) {
  var hline = htmlLines[hi];

  if (hline.match(/^\|[\s\-:|]+\|$/)) {
    continue;
  }

  if (hline.match(/^\|.*\|$/)) {
    if (!inHtmlTable) {
      inHtmlTable = true;
      isHtmlFirstRow = true;
      htmlTableContent = '<table>';
    }
    var hcells = hline.split('|').filter(function(c) { return c.trim() !== ''; });
    var htag = isHtmlFirstRow ? 'th' : 'td';
    htmlTableContent += '<tr>';
    for (var hc = 0; hc < hcells.length; hc++) {
      var cellText = hcells[hc].trim()
        .replace(/\*\*(.*?)\*\*/g, '$1')
        .replace(/\*(.*?)\*/g, '$1');
      htmlTableContent += '<' + htag + '>' + cellText + '</' + htag + '>';
    }
    htmlTableContent += '</tr>';
    isHtmlFirstRow = false;
  } else {
    if (inHtmlTable) {
      htmlTableContent += '</table>';
      htmlResult.push(htmlTableContent);
      htmlTableContent = '';
      inHtmlTable = false;
      isHtmlFirstRow = true;
    }

    var cleanLine = hline;

    // Convert headings and capture for TOC
    if (cleanLine.match(/^#{1,5}\s+/)) {
      var headingLevel = cleanLine.match(/^(#{1,5})\s+/)[1].length;
      var headingText = cleanLine.replace(/^#{1,5}\s+/, '').trim();
      headingText = headingText.replace(/\*\*/g, '');
      headingText = headingText.replace(/\s*#+\s*$/, '');

      // Create anchor ID for linking
      var anchorId = 'section-' + tocEntries.length;
      tocEntries.push({
        level: headingLevel,
        text: headingText,
        id: anchorId
      });

      cleanLine = '<h' + headingLevel + ' id="' + anchorId + '">' + headingText + '</h' + headingLevel + '>';
    }
    else if (cleanLine.match(/^\*\*[^*]+\*\*\s*$/) && cleanLine.length < 100) {
      var boldHeading = cleanLine.replace(/\*\*/g, '').trim();

      var anchorId2 = 'section-' + tocEntries.length;
      tocEntries.push({
        level: 3,
        text: boldHeading,
        id: anchorId2
      });

      cleanLine = '<h3 id="' + anchorId2 + '">' + boldHeading + '</h3>';
    }
    else {
      cleanLine = cleanLine.replace(/\*\*\*(.*?)\*\*\*/g, '<strong><em>$1</em></strong>');
      cleanLine = cleanLine.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
      cleanLine = cleanLine.replace(/\*(.*?)\*/g, '<em>$1</em>');
      cleanLine = cleanLine.replace(/^#+\s*/, '');

      if (cleanLine.trim() === '---' || cleanLine.trim() === '***') {
        cleanLine = '';
      }

      if (cleanLine.trim().length > 5 && !cleanLine.match(/^<h[1-5]/)) {
        cleanLine = '<p>' + cleanLine.trim() + '</p>';
      }
    }

    if (cleanLine.trim()) {
      htmlResult.push(cleanLine);
    }
  }
}

if (inHtmlTable) {
  htmlTableContent += '</table>';
  htmlResult.push(htmlTableContent);
}

var processedContent = htmlResult.join('\n');

processedContent = processedContent
  .replace(/<p>\s*<\/p>/g, '')
  .replace(/<p><\/p>/g, '')
  .replace(/<p>\s*---\s*<\/p>/g, '')
  .replace(/<p>\s*\*\*\*\s*<\/p>/g, '');

// =============================================
// STEP 11: BUILD TABLE OF CONTENTS
// =============================================
var tocHtml = '<div class="toc">';
tocHtml += '<h1>Table of Contents</h1>';
tocHtml += '<div class="toc-list">';

// Number the sections
var sectionNumber = 0;
var subSectionNumber = 0;

for (var ti = 0; ti < tocEntries.length; ti++) {
  var entry = tocEntries[ti];
  var indent = '';
  var prefix = '';

  if (entry.level <= 2) {
    sectionNumber++;
    subSectionNumber = 0;
    prefix = sectionNumber + '.';
    indent = 'toc-level-1';
  } else if (entry.level === 3) {
    subSectionNumber++;
    prefix = sectionNumber + '.' + subSectionNumber;
    indent = 'toc-level-2';
  } else {
    prefix = '';
    indent = 'toc-level-3';
  }

  tocHtml += '<div class="toc-entry ' + indent + '">';
  tocHtml += '<a href="#' + entry.id + '">';
  tocHtml += '<span class="toc-number">' + prefix + '</span>';
  tocHtml += '<span class="toc-text">' + entry.text + '</span>';
  tocHtml += '</a>';
  tocHtml += '</div>';
}

tocHtml += '</div></div>';

// =============================================
// STEP 12: BUILD HTML DOCUMENT
// =============================================
var fullHtml = '<!DOCTYPE html>'
  + '<html lang="en">'
  + '<head>'
  + '<meta charset="UTF-8">'
  + '<title>' + assignmentTitle + '</title>'
  + '<style>'
  + '@page { size: A4; margin: 2.54cm; }'
  + '@media print { .cover { page-break-after: always; } .toc { page-break-after: always; } body { margin: 0; } }'
  + 'body {'
  + '  font-family: Arial, sans-serif;'
  + '  font-size: 11pt;'
  + '  line-height: 1.5;'
  + '  color: #000;'
  + '  margin: 2.54cm;'
  + '}'
  + 'h1 { font-size: 16pt; margin-top: 30px; margin-bottom: 10px; }'
  + 'h2 { font-size: 14pt; margin-top: 28px; margin-bottom: 10px; }'
  + 'h3 { font-size: 13pt; margin-top: 22px; margin-bottom: 8px; }'
  + 'h4 { font-size: 12pt; margin-top: 18px; margin-bottom: 6px; }'
  + 'h5 { font-size: 11pt; margin-top: 14px; margin-bottom: 4px; }'
  + 'p { text-align: justify; margin-bottom: 12px; }'
  + 'table { border-collapse: collapse; width: 100%; margin: 20px 0 10px 0; }'
  + 'th { border: 1px solid #000; padding: 8px 10px; text-align: left; font-size: 10pt; background: #f0f0f0; font-weight: bold; }'
  + 'td { border: 1px solid #000; padding: 8px 10px; text-align: left; font-size: 10pt; }'

  // Cover page styles
  + '.cover { text-align: center; padding-top: 100px; min-height: 90vh; }'
  + '.cover h1 { font-size: 22pt; text-align: center; }'
  + '.cover h2 { font-size: 16pt; font-weight: normal; text-align: center; color: #333; }'
  + '.cover p { font-size: 12pt; margin: 10px 0; text-align: center; }'
  + '.cover .line { border-top: 2px solid #000; width: 60%; margin: 30px auto; }'

  // Table of Contents styles
  + '.toc { padding-top: 40px; min-height: 50vh; }'
  + '.toc h1 { font-size: 18pt; margin-bottom: 30px; }'
  + '.toc-list { margin-top: 20px; }'
  + '.toc-entry { margin-bottom: 10px; font-size: 11pt; }'
  + '.toc-entry a { text-decoration: none; color: #000; display: flex; }'
  + '.toc-entry a:hover { color: #0056b3; }'
  + '.toc-number { min-width: 50px; font-weight: bold; }'
  + '.toc-text { flex: 1; }'
  + '.toc-level-1 { margin-left: 0px; font-weight: bold; }'
  + '.toc-level-2 { margin-left: 30px; font-weight: normal; }'
  + '.toc-level-3 { margin-left: 60px; font-weight: normal; font-size: 10pt; }'

  + '</style>'
  + '</head>'
  + '<body>'

  // COVER PAGE
  + '<div class="cover">'
  + '<h1>' + university.toUpperCase() + '</h1>'
  + '<div class="line"></div>'
  + '<br>'
  + '<h1>' + assignmentTitle.toUpperCase() + '</h1>'
  + (moduleCode ? '<p><strong>Module Code:</strong> ' + moduleCode + '</p>' : '')
  + '<br>'
  + (moduleName !== 'Module' ? '<p><strong>Module:</strong> ' + moduleName + '</p>' : '')
  + (moduleLead ? '<p><strong>Module Lead:</strong> ' + moduleLead + '</p>' : '')
  + (submissionDate ? '<p><strong>Submission Date:</strong> ' + submissionDate + '</p>' : '')
  + '<p><strong>Word Count:</strong> ' + actualWordCount + '</p>'
  + (refStyle ? '<p><strong>Referencing Style:</strong> ' + refStyle + '</p>' : '')
  + (academicLevel ? '<p><strong>Academic Level:</strong> ' + academicLevel + '</p>' : '')
  + '<div class="line"></div>'
  + '<p style="font-size:10pt; color:#666;">Arial 11pt | 1.5 Line Spacing | A4 Format | 2.54cm Margins</p>'
  + '</div>'

  // TABLE OF CONTENTS
  + tocHtml

  // REPORT CONTENT
  + processedContent

  + '</body></html>';

// =============================================
// STEP 13: CREATE DOWNLOADABLE FILE
// =============================================
var buffer = Buffer.from(fullHtml, 'utf-8');

var safeTitle = assignmentTitle
  .replace(/[^a-zA-Z0-9\s]/g, '')
  .replace(/\s+/g, '_')
  .substring(0, 50);

var fileName = 'Assignment_' + safeTitle + '.html';

return [{
  json: {
    assignmentTitle: assignmentTitle,
    university: university,
    moduleName: moduleName,
    moduleCode: moduleCode,
    academicLevel: academicLevel,
    referencingStyle: refStyle,
    actualWordCount: actualWordCount,
    requiredWordCount: requiredWordCount,
    wordDifference: actualWordCount - requiredWordCount,
    tableCount: tableCount,
    referenceCount: refCount,
    citationCount: citationCount,
    wordCountPass: wordOk,
    tablesPass: tablesOk,
    referencesPass: refsOk,
    citationsPass: citationsOk,
    referencingAllowed: referencingAllowed,
    allPassed: allPassed,
    status: allPassed ? 'PASS' : 'NEEDS REVIEW',
    fileName: fileName,
    tocSections: tocEntries.length
  },
  binary: {
    attachment: {
      data: buffer.toString('base64'),
      mimeType: 'text/html',
      fileName: fileName,
      fileExtension: 'html'
    }
  }
}];
